import type React from 'react';
import { useCssScope } from '../config-provider/hooks';
import type { AvatarProps } from './Avatar';

/**
 * 用于标识该组件是 ud avatar 组件
 */
export const UD_AVATAR_ID = 'UD_AVATAR';
export const useAvatarCssScope = () => useCssScope('avatar');
export const useAvatarGroupCssScope = () => useCssScope('avatar-group');
export function isAvatar(node: any): node is React.ReactElement<AvatarProps> {
  return node?.type?.[UD_AVATAR_ID];
}
